import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Home.css";

const Home = () => {
  const navigate = useNavigate();
  const [events, setEvents] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/events")
      .then(res => res.json())
      .then(data => setEvents(data));
  }, []);

  const topEvents = events.slice(0, 6);

  return (
    <div className="home">

      {/* 🔥 HERO */}
      <section className="hero">
        <div className="hero-content">
          <h1>Знайди свою ідеальну подію</h1>
          <p>Конференції, воркшопи, зустрічі по всьому світу</p>

          <button onClick={() => navigate("/events")} className="cta-btn">
            Переглянути події
          </button>
        </div>
      </section>

      {/* 🔹 КАТЕГОРИИ */}
      <section className="categories">
        <h2>Категорії</h2>

        <div className="category-grid">
          {["IT", "Business", "Design", "Marketing", "Education"].map(cat => (
            <div
              key={cat}
              className="category-card"
              onClick={() => navigate(`/events?category=${cat}`)}
            >
              {cat}
            </div>
          ))}
        </div>
      </section>

      {/* 🔥 ПОПУЛЯРНЫЕ СОБЫТИЯ */}
      <section className="top-events">
        <h2>Популярні події</h2>

        <div className="events-grid">
          {topEvents.map(event => (
            <div
              key={event.id}
              className="event-card"
              onClick={() => navigate(`/events/${event.id}`)}
            >
              <div
                className="event-image"
                style={{ backgroundImage: `url(${event.image})` }}
              />

              <div className="event-info">
                <h3>{event.title}</h3>
                <p>{event.location}</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* 🔹 WHY US */}
      <section className="features">
        <h2>Чому обирають нас</h2>

        <div className="features-grid">
          <div className="feature">
            <h3>🌍 Події по всьому світу</h3>
            <p>Знаходь івенти в будь-якій країні</p>
          </div>

          <div className="feature">
            <h3>⚡ Швидка реєстрація</h3>
            <p>Записуйся за кілька секунд</p>
          </div>

          <div className="feature">
            <h3>📊 Актуальна інформація</h3>
            <p>Тільки перевірені події</p>
          </div>
        </div>
      </section>

      {/* 🔥 CTA */}
      <section className="cta">
        <h2>Не пропусти свою можливість 🚀</h2>
        <button onClick={() => navigate("/events")} className="cta-btn">
          Знайти подію
        </button>
      </section>

    </div>
  );
};

export default Home;
